#include <stdio.h> // Required for input/output functions like printf and scanf

int main() {
    int num1; // Declare an integer variable to store the first number
    int num2; // Declare an integer variable to store the second number

    // Read two integers from standard input
    if (scanf("%d %d", &num1, &num2) != 2) {
        fprintf(stderr, "Error: Invalid input. Please enter two integers.\n");
        return 1; // Indicate an error
    }

    // Perform arithmetic operations and store results in variables
    int sum = num1 + num2;
    int difference = num1 - num2;
    int product = num1 * num2;

    // Print the results for sum, difference, and product
    printf("Sum: %d\n", sum);
    printf("Difference: %d\n", difference);
    printf("Product: %d\n", product);

    // Handle division by zero explicitly
    if (num2 == 0) {
        printf("Quotient: Division by zero is not allowed.\n");
    } else {
        int quotient = num1 / num2; // Perform integer division
        printf("Quotient: %d\n", quotient);
    }

    return 0; // Indicate successful execution
}
